/* Prof. Filer — app.js. Zero Python. window.CONFIG from index.html. */

var M = window.CONFIG.mascot;

function go(id) {
  var pages = document.querySelectorAll('.pg');
  for (var i = 0; i < pages.length; i++) pages[i].classList.remove('on');
  var navLinks = document.querySelectorAll('.nl a[id]');
  for (var i = 0; i < navLinks.length; i++) navLinks[i].classList.remove('on');
  var page = document.getElementById('pg-' + id);
  if (page) page.classList.add('on');
  var nav = document.getElementById('na-' + id);
  if (nav) nav.classList.add('on');
  window.scrollTo(0, 0);
  if (id === 'quiz' && !window._QI) { window._QI = true; renderQuiz(); }
}

window._QI = false;
var QP = 'intro', QC = 0, QA = {}, QR = '', DOCS = [];
var RPT = {}; // parsed report sections

var QS = [
  {id:1,t:'r',q:'When attending a social event, you prefer to:',
   os:['Engage with many people briefly','Focus on a few close friends','Observe quietly from the sidelines','Arrive late and leave early']},
  {id:2,t:'s',q:'How much do you rely on concrete facts versus abstract ideas when solving problems?',lo:'Concrete facts',hi:'Abstract ideas'},
  {id:3,t:'x',q:'Rate your comfort level with making decisions based on feelings rather than logic:'},
  {id:4,t:'r',q:'When organizing your day, you tend to:',
   os:['Plan everything in advance','Make a loose plan and adapt','Go with the flow without plans','Focus on urgent tasks only']},
  {id:5,t:'s',q:'How much do you enjoy spontaneous activities compared to scheduled ones?',lo:'Prefer scheduled',hi:'Love spontaneous'},
  {id:6,t:'x',q:'Rate how often you trust your intuition over practical experience:'},
  {id:7,t:'r',q:'In conversations, you usually:',
   os:['Speak more than listen','Listen more than speak','Balance speaking and listening','Prefer written communication']},
  {id:8,t:'s',q:'How important is emotional harmony in your relationships?',lo:'Not very important',hi:'Extremely important'},
  {id:9,t:'x',q:'Rate your preference for sticking to routines versus seeking new experiences:'},
  {id:10,t:'r',q:'When faced with a conflict, you tend to:',
   os:["Address it directly and logically","Try to understand everyone's feelings","Avoid confrontation whenever possible","Look for a compromise quickly"]},
];

function renderQuiz() {
  var root = document.getElementById('qroot');
  if (!root) return;
  if (QP === 'intro')        root.innerHTML = tmplIntro();
  else if (QP === 'quiz')    root.innerHTML = tmplQ();
  else if (QP === 'docs')    root.innerHTML = tmplDocs();
  else if (QP === 'loading') root.innerHTML = tmplLoad();
  else                       root.innerHTML = tmplReport();
}

function tmplIntro() {
  var h = '<div class="qic">';
  h += '<img src="'+M+'" height="76" alt="Prof. Filer" style="display:inline-block">';
  h += '<h2>Personality Assessment</h2>';
  h += '<p style="font-size:14px;color:#7C7E7D;line-height:1.65;margin-bottom:4px">10 questions &amp; 3 documents. Under 5 minutes.<br>A surprisingly accurate read on how you think, feel, and move through the world.</p>';
  h += '<div class="qdge">&#128274; Your answers are processed privately and never stored on our servers.</div>';
  h += '<button class="qbtn" onclick="QP=\'quiz\';QC=0;renderQuiz()" style="width:100%;font-size:15px;padding:14px;margin-top:4px">Begin Assessment &#8594;</button>';
  h += '</div>';
  return h;
}

function tmplQ() {
  var q=QS[QC], a=QA[q.id], pct=Math.round(QC/QS.length*100);
  var last=(QC===QS.length-1), hasA=(a!==undefined);
  if (q.t==='s' && a===undefined) { QA[q.id]=5; a=5; }
  var inp='';
  if (q.t==='r') {
    for (var i=0;i<q.os.length;i++) {
      var v=String.fromCharCode(65+i), sel=(a===v)?' on':'';
      inp+='<div class="qo'+sel+'" onclick="qsa('+q.id+',\''+v+'\')">';
      inp+='<div class="qrd"><div class="qdot"></div></div>'+q.os[i]+'</div>';
    }
  } else if (q.t==='s') {
    var v2=a||5;
    inp='<div style="padding:6px 0 2px"><input type="range" min="1" max="10" value="'+v2+'" step="1"';
    inp+=' oninput="qsa('+q.id+',+this.value);document.getElementById(\'sv'+q.id+'\').textContent=this.value+\'/10\'">';
    inp+='<div class="qsv"><span class="qsl">'+q.lo+'</span><span class="qsval" id="sv'+q.id+'">'+v2+'/10</span><span class="qsl">'+q.hi+'</span></div></div>';
  } else {
    var v3=a||0;
    inp='<div class="qstars">';
    for (var s=1;s<=5;s++) inp+='<button class="qstar'+(s<=v3?' on':'')+'" onclick="qsa('+q.id+','+s+')">&#9733;</button>';
    inp+='</div>';
  }
  var h='<div class="qcard">';
  h+='<div class="qpr"><div class="qpf" style="width:'+pct+'%"></div></div>';
  h+='<div class="qmeta"><span class="qlbl">Question '+(QC+1)+' of '+QS.length+'</span><span class="qlbl">'+pct+'% complete</span></div>';
  h+='<div class="qq">'+q.q+'</div>'+inp;
  h+='<div class="qbtns">';
  h+=(QC>0?'<button class="qbtn2" onclick="qprev()">&#8592; Back</button>':'<button class="qbtn2" onclick="QP=\'intro\';renderQuiz()">&#8592; Back</button>');
  h+='<button class="qbtn"'+(hasA?'':' disabled')+' onclick="qnext()">'+(last?'Upload Documents &#8594;':'Next &#8594;')+'</button></div></div>';
  return h;
}

function tmplDocs() {
  var uploaded=DOCS.length, allDone=(uploaded>=3);
  var dropArea='';
  if (!allDone) {
    dropArea='<div class="doc-drop" onclick="document.getElementById(\'docInput\').click()">';
    dropArea+='<div style="font-size:36px;margin-bottom:10px">&#8679;</div>';
    dropArea+='<strong>'+(uploaded>0?uploaded+' of 3 uploaded \u2014 add '+(3-uploaded)+' more':'Click to upload your documents')+'</strong>';
    dropArea+='<p style="font-size:12px;color:#7C7E7D;margin-top:6px">PDF, Word, or text files that reflect your writing style</p>';
    dropArea+='<input type="file" id="docInput" accept=".pdf,.doc,.docx,.txt" multiple style="display:none" onchange="handleDocUpload(this)">';
    dropArea+='</div>';
  } else {
    dropArea='<div class="doc-drop doc-drop-done">';
    dropArea+='<div style="font-size:36px;margin-bottom:8px">&#10003;</div>';
    dropArea+='<strong style="color:#22a85a">All documents uploaded!</strong>';
    dropArea+='<p style="font-size:12px;color:#7C7E7D;margin-top:4px">3 of 3 documents uploaded</p>';
    dropArea+='</div>';
  }
  var docList='';
  for (var i=0;i<DOCS.length;i++) {
    docList+='<div class="doc-item"><div class="doc-icon">&#128196;</div><div class="doc-name">'+escHtml(DOCS[i])+'</div>';
    docList+='<button class="doc-remove" onclick="removeDoc('+i+')">&#215;</button></div>';
  }
  var h='<div class="qcard">';
  h+='<div style="text-align:center;margin-bottom:20px">';
  h+='<h2 style="font-family:SFOrsonCasual,sans-serif;font-size:22px;color:#2D4C68;text-transform:uppercase;letter-spacing:.05em">Upload Your Documents</h2>';
  h+='<p style="font-size:14px;color:#7C7E7D;margin-top:8px">Share 3 documents that reflect your writing style \u2014 reports, proposals, analyses, prose, etc.</p>';
  h+='</div>'+dropArea;
  if (docList) h+='<div class="doc-list">'+docList+'</div>';
  h+='<div style="font-size:12px;color:#9AAAB8;text-align:center;margin-top:14px;line-height:1.6">All documents remain entirely yours. Processed privately, never stored.</div>';
  h+='<div class="qbtns" style="margin-top:20px">';
  h+='<button class="qbtn2" onclick="QP=\'quiz\';QC=QS.length-1;renderQuiz()">&#8592; Back</button>';
  h+='<button class="qbtn" '+(allDone?'':'disabled')+' onclick="submitQuiz()">Get My Report &#8594;</button>';
  h+='</div></div>';
  return h;
}

function escHtml(s){ return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function handleDocUpload(input){ var f=input.files; for(var i=0;i<f.length;i++) if(DOCS.length<3) DOCS.push(f[i].name); renderQuiz(); }
function removeDoc(idx){ DOCS.splice(idx,1); renderQuiz(); }

function tmplLoad() {
  var h='<div class="qcard" style="text-align:center;padding:38px 28px">';
  h+='<img src="'+M+'" height="58" style="display:inline-block;margin-bottom:12px" alt="">';
  h+='<div style="font-family:GilroyBold,sans-serif;font-size:18px;color:#2D4C68;margin-bottom:6px">Prof. Filer is running the numbers\u2026</div>';
  h+='<div style="font-size:13px;color:#7C7E7D;margin-bottom:2px">Analysing your responses across 40+ behavioural indicators.</div>';
  h+='<div class="qldots"><div class="qdot2" style="animation-delay:0s"></div><div class="qdot2" style="animation-delay:.2s"></div><div class="qdot2" style="animation-delay:.4s"></div></div>';
  h+='<div style="font-size:11px;color:#9AAAB8">Usually takes 10\u201320 seconds</div></div>';
  return h;
}

// ── Parse the AI report into named sections ───────────────────────────────
function parseReport(raw) {
  var r = { raw:raw, type:'', typeName:'', typeDesc:'', overview:'', strengths:[], watchFor:[], verdict:'' };
  var typeMatch = raw.match(/\*\*Your Personality Type\*\*\s*\n([^\n]+)/);
  if (typeMatch) {
    var parts = typeMatch[1].trim().split(/\s*[\u2014\-]{1,2}\s*/);
    r.type     = parts[0] ? parts[0].trim() : '';
    r.typeName = parts[1] ? parts[1].trim() : '';
    r.typeDesc = parts[2] ? parts[2].trim() : '';
  }
  var readMatch = raw.match(/\*\*The Prof\.[\u2019']?s Reading\*\*\s*\n([\s\S]*?)(?=\*\*Your Superpowers|\*\*Watch Out|\*\*Prof\.|$)/);
  r.overview = readMatch ? readMatch[1].trim() : '';
  var spMatch = raw.match(/\*\*Your Superpowers\*\*\s*\n([\s\S]*?)(?=\*\*Watch Out|\*\*Prof\.|$)/);
  if (spMatch) r.strengths = spMatch[1].trim().split('\n').filter(function(l){return l.trim();}).map(function(l){return l.replace(/^[•\-\*\u2022]\s*/,'').trim();});
  var woMatch = raw.match(/\*\*Watch Out For\*\*\s*\n([\s\S]*?)(?=\*\*Prof\.|$)/);
  if (woMatch) r.watchFor = woMatch[1].trim().split('\n').filter(function(l){return l.trim();}).map(function(l){return l.replace(/^[•\-\*\u2022]\s*/,'').trim();});
  var vMatch = raw.match(/\*\*Prof\. Filer[''\u2019]?s Verdict\*\*\s*\n([\s\S]*?)$/);
  r.verdict = vMatch ? vMatch[1].trim() : '';
  return r;
}

// ── On-screen report — full free content, no paywall ─────────────────────
function tmplReport() {
  var isErr = !QR || QR.indexOf('API error')===0 || QR.indexOf('Connection error')===0;
  if (isErr) {
    var h='<div class="qcard"><div style="text-align:center;padding:20px 0">';
    h+='<div style="font-size:36px;margin-bottom:12px">&#128561;</div>';
    h+='<div style="font-family:GilroyBold,sans-serif;font-size:17px;color:#D12019;margin-bottom:10px">Could not generate report</div>';
    h+='<div style="font-size:13px;color:#7C7E7D;line-height:1.6;margin-bottom:8px">'+escHtml(QR)+'</div>';
    h+='<div style="font-size:12px;color:#9AAAB8;line-height:1.6">Make sure <strong>OPENAI_API_KEY</strong> is set in Vercel environment variables, then redeploy.</div>';
    h+='</div><div class="qbtns" style="margin-top:20px"><button class="qbtn" onclick="QP=\'docs\';renderQuiz()">Try Again</button></div></div>';
    return h;
  }

  RPT = parseReport(QR);
  var overviewHtml = RPT.overview.split('\n').map(function(l){return l.trim()?'<p style="margin-bottom:10px">'+l+'</p>':'';}).join('');

  var h='<div class="qcard">';

  // Header
  h+='<div class="qrh"><img src="'+M+'" height="48" alt="Prof. Filer">';
  h+='<div><div style="font-size:10px;color:#7C7E7D;letter-spacing:.1em;text-transform:uppercase">Your AI Analysis Complete</div>';
  h+='<div style="font-family:SFOrsonCasual,sans-serif;font-size:26px;color:#2D4C68;text-transform:uppercase;letter-spacing:.05em">'+escHtml(RPT.type)+'</div>';
  if (RPT.typeName) h+='<div style="font-family:GilroyBold,sans-serif;font-size:15px;color:#5086AD">'+escHtml(RPT.typeName)+'</div>';
  if (RPT.typeDesc) h+='<div style="font-size:13px;color:#7C7E7D">'+escHtml(RPT.typeDesc)+'</div>';
  h+='</div></div>';

  // Prof's Reading
  h+='<div style="margin-bottom:20px">';
  h+='<div style="font-size:11px;font-family:GilroyBold,sans-serif;color:#D12019;letter-spacing:.1em;text-transform:uppercase;margin-bottom:10px">The Prof\'s Reading</div>';
  h+='<div class="qrb">'+overviewHtml+'</div>';
  h+='</div>';

  // Superpowers
  if (RPT.strengths.length) {
    h+='<div style="margin-bottom:20px">';
    h+='<div style="font-size:11px;font-family:GilroyBold,sans-serif;color:#D12019;letter-spacing:.1em;text-transform:uppercase;margin-bottom:10px">Your Superpowers</div>';
    for (var i=0;i<RPT.strengths.length;i++) {
      h+='<div style="display:flex;align-items:flex-start;gap:10px;padding:11px 14px;background:#FFF4EC;border-radius:8px;margin-bottom:8px;border-left:3px solid #FFC499">';
      h+='<span style="color:#D12019;margin-top:1px;flex-shrink:0">&#9733;</span>';
      h+='<span style="font-size:14px;color:#2D4C68;line-height:1.5">'+escHtml(RPT.strengths[i])+'</span></div>';
    }
    h+='</div>';
  }

  // Watch Out For
  if (RPT.watchFor.length) {
    h+='<div style="margin-bottom:20px">';
    h+='<div style="font-size:11px;font-family:GilroyBold,sans-serif;color:#5086AD;letter-spacing:.1em;text-transform:uppercase;margin-bottom:10px">Watch Out For</div>';
    for (var j=0;j<RPT.watchFor.length;j++) {
      h+='<div style="display:flex;align-items:flex-start;gap:10px;padding:11px 14px;background:#F0F5F9;border-radius:8px;margin-bottom:8px;border-left:3px solid #5086AD">';
      h+='<span style="color:#5086AD;margin-top:1px;flex-shrink:0">&#8594;</span>';
      h+='<span style="font-size:14px;color:#2D4C68;line-height:1.5">'+escHtml(RPT.watchFor[j])+'</span></div>';
    }
    h+='</div>';
  }

  // Verdict
  if (RPT.verdict) {
    h+='<div style="background:#2D4C68;border-radius:10px;padding:18px 22px;margin-bottom:20px">';
    h+='<div style="font-size:10px;color:rgba(255,255,255,.45);letter-spacing:.12em;text-transform:uppercase;margin-bottom:8px">Prof. Filer\'s Verdict</div>';
    h+='<div style="font-size:15px;color:#FFC499;font-family:GilroyMedium,sans-serif;font-style:italic;line-height:1.6">\u201c'+escHtml(RPT.verdict)+'\u201d</div>';
    h+='</div>';
  }

  // Download full PDF button
  h+='<div style="background:linear-gradient(135deg,#FFF4EC,#FFE8D4);border-radius:12px;padding:22px;margin-bottom:20px;border:1px solid #FFD4B8;text-align:center">';
  h+='<div style="font-family:GilroyBold,sans-serif;font-size:15px;color:#2D4C68;margin-bottom:6px">Want the full picture?</div>';
  h+='<div style="font-size:13px;color:#7C7E7D;margin-bottom:14px">Download your complete 7-page personality report \u2014 cognitive functions, career paths, relationships, leadership style, stress response &amp; more.</div>';
  h+='<button class="qbtn" class="qbtn dl-pdf-btn" style="background:#D12019;width:auto;padding:12px 28px" onclick="downloadFullPDF()">&#8681; Download Full Report PDF</button>';
  h+='<div style="font-size:11px;color:#9AAAB8;margin-top:8px">Free for now \u2022 PDF \u2022 7 pages</div>';
  h+='</div>';

  h+='<div class="qdisc">Prof. Filer is an independent AI-based personality assessment tool and is not affiliated with or endorsed by the Myers-Briggs Type Indicator&#174; or The Myers-Briggs Company. For informational purposes only.</div>';
  h+='<div class="qbtns" style="margin-top:18px"><button class="qbtn2" onclick="retakeQuiz()">Retake Assessment</button><button class="qbtn2" onclick="copyReport()">Copy Text</button></div>';
  h+='</div>';
  return h;
}


var FONT_REGULAR = "";
var FONT_MEDIUM = "";
var FONT_MEDIUMITALIC = "";
var FONT_SEMIBOLD = "";
var FONT_SEMIBOLDITALIC = "";
var FONT_EXTRABOLD = "";
var FONT_HEAVY = "";
var PDF_LOGO = "data:image/webp;base64,";
// ── PDF Generation (jsPDF, loaded on demand) ─────────────────────────────
function downloadFullPDF() {
  var btn = document.querySelector('.dl-pdf-btn');
  if (btn) { btn.disabled=true; btn.innerHTML='Generating PDF\u2026'; }
  if (window.jspdf && window.jspdf.jsPDF) { _buildPDF(btn); return; }
  var s = document.createElement('script');
  s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';
  s.onload = function(){ _buildPDF(btn); };
  s.onerror = function(){
    alert('Could not load PDF library. Check your internet connection.');
    if(btn){btn.disabled=false;btn.innerHTML='&#8681; Download Full Report PDF';}
  };
  document.head.appendChild(s);
}

function _buildPDF(triggerBtn) {
  try {
    var jsPDF = window.jspdf.jsPDF;
    var doc = new jsPDF({orientation:'portrait',unit:'mm',format:'a4'});
    var PW=210, PH=297, MAR=18, CW=174;

    // Register Gilroy fonts
    doc.addFileToVFS('Gilroy-Regular.ttf',    FONT_REGULAR);    doc.addFont('Gilroy-Regular.ttf',    'Gilroy','normal');
    doc.addFileToVFS('Gilroy-Medium.ttf',     FONT_MEDIUM);     doc.addFont('Gilroy-Medium.ttf',     'Gilroy','medium');
    doc.addFileToVFS('Gilroy-MediumItalic.ttf',FONT_MEDIUMITALIC);doc.addFont('Gilroy-MediumItalic.ttf','Gilroy','mediumitalic');
    doc.addFileToVFS('Gilroy-SemiBold.ttf',   FONT_SEMIBOLD);   doc.addFont('Gilroy-SemiBold.ttf',   'Gilroy','semibold');
    doc.addFileToVFS('Gilroy-ExtraBold.ttf',  FONT_EXTRABOLD);  doc.addFont('Gilroy-ExtraBold.ttf',  'Gilroy','extrabold');
    doc.addFileToVFS('Gilroy-Heavy.ttf',      FONT_HEAVY);      doc.addFont('Gilroy-Heavy.ttf',      'Gilroy','heavy');

    // Palette
    var NAVY=[45,76,104], RED=[209,32,25], BLUE=[80,134,173];
    var PEACH=[255,196,153], GREY=[124,126,125], LIGHT=[240,245,249];
    var WHITE=[255,255,255], DARK=[30,52,72], PINK=[255,244,236];
    var MID=[55,75,95];

    var y = 0;
    var LH = 5.8; // line height for body text

    function sf(c){ doc.setFillColor(c[0],c[1],c[2]); }
    function sd(c){ doc.setDrawColor(c[0],c[1],c[2]); }
    function st(c){ doc.setTextColor(c[0],c[1],c[2]); }
    function gf(w){ doc.setFont('Gilroy', w||'normal'); }

    var TYPE = RPT.type || 'XXXX';
    var td = getTypeData(TYPE);

    // ── needSpace: add new page if not enough room ────────────────────────
    function needSpace(n) {
      if (y + n > PH - 16) {
        doc.addPage();
        sf(NAVY); doc.rect(0,0,PW,5,'F');
        y = 16;
      }
    }

    // ── Section bar ───────────────────────────────────────────────────────
    function secBar(title, col) {
      col = col || NAVY;
      needSpace(14);
      sf(col); doc.roundedRect(MAR, y, CW, 9, 2, 2, 'F');
      st(WHITE); gf('extrabold'); doc.setFontSize(8.5);
      doc.text(title.toUpperCase(), MAR+4, y+6);
      y += 13;
    }

    // ── Sub-heading ───────────────────────────────────────────────────────
    function subHead(title, col) {
      col = col || RED;
      needSpace(10);
      gf('semibold'); doc.setFontSize(10.5); st(col);
      doc.text(title, MAR, y);
      y += 6.5;
    }

    // ── Body paragraph ────────────────────────────────────────────────────
    function bodyPara(text) {
      if (!text || !text.trim()) return;
      needSpace(10);
      gf('normal'); doc.setFontSize(9.5); st(MID);
      var lines = doc.splitTextToSize(text, CW);
      needSpace(lines.length * LH + 2);
      doc.text(lines, MAR, y, {lineHeightFactor:1.6});
      y += lines.length * LH + 6;
    }

    // ── Bullet item ───────────────────────────────────────────────────────
    function bullet(text, dotCol, bgCol) {
      dotCol = dotCol || RED;
      bgCol  = bgCol  || LIGHT;
      if (!text || !text.trim()) return;
      var lines = doc.splitTextToSize(text, CW-13);
      var bh = Math.max(8, lines.length * LH + 5);
      needSpace(bh + 2);
      sf(bgCol); doc.roundedRect(MAR, y, CW, bh, 2, 2, 'F');
      sf(dotCol); doc.circle(MAR+5, y + bh/2, 1.6, 'F');
      gf('normal'); doc.setFontSize(9.5); st(NAVY);
      doc.text(lines, MAR+10, y + (bh - lines.length*LH)/2 + LH, {lineHeightFactor:1.6});
      y += bh + 3;
    }

    // ── Numbered item ─────────────────────────────────────────────────────
    function numberedItem(n, text) {
      if (!text) return;
      var lines = doc.splitTextToSize(text, CW-9);
      var bh = lines.length * LH + 4;
      needSpace(bh + 2);
      gf('extrabold'); doc.setFontSize(9.5); st(RED);
      doc.text(n+'.', MAR, y + LH);
      gf('normal'); st(MID);
      doc.text(lines, MAR+7, y + LH, {lineHeightFactor:1.6});
      y += bh + 3;
    }

    // ════════════════════════════════════════════════════════════════════════
    // PAGE 1: COVER
    // ════════════════════════════════════════════════════════════════════════
    sf(NAVY); doc.rect(0,0,PW,80,'F');

    // Prof. Filer logo centred in navy zone
    try {
      // Logo at top of navy block, centred
      var logoW = 28, logoH = 28;
      doc.addImage(PDF_LOGO,'WEBP', PW/2-logoW/2, 8, logoW, logoH);
    } catch(e) {
      sf(RED); doc.circle(PW/2, 22, 10, 'F');
      st(WHITE); gf('extrabold'); doc.setFontSize(12);
      doc.text('PF', PW/2, 25.5, {align:'center'});
    }

    // "Full Personality Report" pill — centred below logo in navy zone
    var pillY = 40;
    sf([255,240,235]);
    doc.roundedRect(PW/2-32, pillY, 64, 8, 3, 3, 'F');
    st(RED); gf('semibold'); doc.setFontSize(8);
    // Vertically centre text in pill shape
    doc.text('Full Personality Report', PW/2, pillY + 5.2, {align:'center'});

    // Type code — large, below pill
    st(WHITE); gf('heavy'); doc.setFontSize(46);
    doc.text(TYPE, PW/2, 70, {align:'center'});

    // White band for type name
    sf(WHITE); doc.rect(0,79,PW,20,'F');
    st(NAVY); gf('extrabold'); doc.setFontSize(18);
    doc.text(RPT.typeName||'', PW/2, 91, {align:'center'});

    // Population blurb — centred below type name
    st(GREY); gf('normal'); doc.setFontSize(9);
    var blurb = td.blurb||'';
    var bLines = doc.splitTextToSize(blurb, 160);
    doc.text(bLines, PW/2, 101, {align:'center', lineHeightFactor:1.55});
    y = 101 + bLines.length * 5.2 + 8;

    // Overview
    secBar('Overview');
    for (var i=0; i<td.overview.length; i++) bodyPara(td.overview[i]);

    // Core Characteristics
    secBar('Core Characteristics');
    for (var i=0; i<td.characteristics.length; i++) bullet(td.characteristics[i], NAVY, LIGHT);

    // ════════════════════════════════════════════════════════════════════════
    // THE PROF'S READING — personalised AI section
    // ════════════════════════════════════════════════════════════════════════
    secBar("The Prof\u2019s Reading", RED);
    var overParts = (RPT.overview||'').split('\n').filter(function(l){return l.trim();});
    for (var i=0; i<overParts.length; i++) bodyPara(overParts[i]);
    y += 2;

    secBar('Your Superpowers');
    for (var i=0; i<RPT.strengths.length; i++) bullet(RPT.strengths[i], RED, PINK);
    y += 2;

    secBar('Areas to Watch', BLUE);
    for (var i=0; i<RPT.watchFor.length; i++) bullet(RPT.watchFor[i], BLUE, LIGHT);
    y += 2;

    // Verdict callout
    if (RPT.verdict) {
      needSpace(26);
      sf(NAVY); doc.roundedRect(MAR, y, CW, 22, 3, 3, 'F');
      st(PEACH); gf('mediumitalic'); doc.setFontSize(9.5);
      var vLines = doc.splitTextToSize('\u201c'+RPT.verdict+'\u201d', CW-14);
      var vTextY = y + (22 - vLines.length*LH)/2 + LH;
      doc.text(vLines, PW/2, vTextY, {align:'center', lineHeightFactor:1.6});
      st(WHITE); gf('normal'); doc.setFontSize(7.5);
      doc.text("Prof. Filer\u2019s Verdict", PW/2, y+20, {align:'center'});
      y += 28;
    }

    // ════════════════════════════════════════════════════════════════════════
    // COGNITIVE FUNCTIONS
    // ════════════════════════════════════════════════════════════════════════
    secBar('Cognitive Functions');
    var fColors = [RED, BLUE, BLUE, GREY];
    for (var i=0; i<td.cognitiveFunctions.length; i++) {
      needSpace(24);
      gf('semibold'); doc.setFontSize(10.5); st(fColors[i]||NAVY);
      doc.text(td.cognitiveFunctions[i].label+': '+td.cognitiveFunctions[i].name, MAR, y);
      y += 6;
      bodyPara(td.cognitiveFunctions[i].desc);
    }
    y += 2;

    // ════════════════════════════════════════════════════════════════════════
    // FAMOUS PEOPLE — 2-column grid
    // ════════════════════════════════════════════════════════════════════════
    if (td.famous && td.famous.length > 0) {
      secBar('Famous People with This Type');
      var fam = td.famous;
      var famHalf = Math.ceil(fam.length/2);
      var famStart = y;
      needSpace(famHalf * 9 + 4);
      for (var i=0; i<fam.length; i++) {
        var cx = (i<famHalf) ? MAR : MAR+CW/2+2;
        var cy = famStart + (i<famHalf ? i : i-famHalf)*9;
        sf(LIGHT); doc.roundedRect(cx, cy, CW/2-3, 7, 2, 2, 'F');
        sf(RED);   doc.circle(cx+5, cy+3.5, 1.5, 'F');
        gf('normal'); doc.setFontSize(9.5); st(NAVY);
        doc.text(fam[i], cx+9, cy+4.8);
      }
      y = famStart + famHalf*9 + 8;
    }

    // ════════════════════════════════════════════════════════════════════════
    // CAREERS — 2-column grid
    // ════════════════════════════════════════════════════════════════════════
    secBar('Ideal Career Paths');
    var cars = td.careers;
    var carHalf = Math.ceil(cars.length/2);
    var carStart = y;
    needSpace(carHalf * 9 + 4);
    for (var i=0; i<cars.length; i++) {
      var cx = (i<carHalf) ? MAR : MAR+CW/2+2;
      var cy = carStart + (i<carHalf ? i : i-carHalf)*9;
      sf(LIGHT); doc.roundedRect(cx, cy, CW/2-3, 7, 2, 2, 'F');
      sf(RED);   doc.circle(cx+5, cy+3.5, 1.5, 'F');
      gf('normal'); doc.setFontSize(9.5); st(NAVY);
      doc.text(cars[i], cx+9, cy+4.8);
    }
    y = carStart + carHalf*9 + 8;

    // ════════════════════════════════════════════════════════════════════════
    // RELATIONSHIPS
    // ════════════════════════════════════════════════════════════════════════
    secBar('Relationships', NAVY);
    subHead('Overview', BLUE);
    bodyPara(td.relationships.overview);
    subHead('Friendships', BLUE);
    bodyPara(td.relationships.friendships);
    subHead('Romantic Relationships', BLUE);
    bodyPara(td.relationships.romantic);
    subHead('Parenting', BLUE);
    bodyPara(td.relationships.parenting);
    y += 2;

    secBar('Compatible Types');
    for (var i=0; i<td.compatible.length; i++) bullet(td.compatible[i], BLUE, LIGHT);
    y += 2;

    secBar('Decision Making');
    bodyPara(td.decisionMaking);
    y += 2;

    secBar('Learning Style');
    bodyPara(td.learningStyle);
    y += 2;

    // ════════════════════════════════════════════════════════════════════════
    // LEADERSHIP / STRESS / ENVIRONMENT — all populated
    // ════════════════════════════════════════════════════════════════════════
    secBar('Leadership Style');
    bodyPara(td.leadership);
    y += 2;

    secBar('Stress Response');
    bodyPara(td.stress);
    y += 2;

    secBar('Ideal Environment');
    bodyPara(td.environment);
    y += 2;

    // ════════════════════════════════════════════════════════════════════════
    // GROWTH + WORK-LIFE — substantive bullets
    // ════════════════════════════════════════════════════════════════════════
    secBar('Growth Opportunities');
    for (var i=0; i<td.growth.length; i++) bullet(td.growth[i], NAVY, LIGHT);
    y += 2;

    secBar('Work-Life Balance');
    for (var i=0; i<td.workLife.length; i++) bullet(td.workLife[i], BLUE, LIGHT);
    y += 2;

    // ════════════════════════════════════════════════════════════════════════
    // HABITS + MOTIVATIONS + FEARS
    // ════════════════════════════════════════════════════════════════════════
    secBar('Recommended Daily Habits');
    for (var i=0; i<td.habits.length; i++) bullet(td.habits[i], NAVY, LIGHT);
    y += 2;

    secBar('Core Motivations');
    for (var i=0; i<td.motivations.length; i++) bullet(td.motivations[i],[200,155,80],[255,250,240]);
    y += 2;

    secBar('Core Fears', RED);
    for (var i=0; i<td.fears.length; i++) numberedItem(i+1, td.fears[i]);
    y += 6;

    // ════════════════════════════════════════════════════════════════════════
    // DISCLAIMER — centred text
    // ════════════════════════════════════════════════════════════════════════
    needSpace(30);
    sf([245,245,245]); sd([200,200,200]);
    doc.setLineWidth(0.3);
    doc.roundedRect(MAR, y, CW, 26, 3, 3, 'FD');
    gf('semibold'); doc.setFontSize(8.5); st([80,80,80]);
    doc.text('Disclaimer', PW/2, y+7, {align:'center'});
    gf('normal'); doc.setFontSize(8); st([120,120,120]);
    var disc = 'Insights provided are for informational purposes only and we make no warranties, express or implied. By using this site, you agree to hold the site owners and distributors harmless from any loss or liability arising from its use. Prof. Filer is not affiliated with or endorsed by The Myers-Briggs Company.';
    var dLines = doc.splitTextToSize(disc, CW-18);
    doc.text(dLines, PW/2, y+14, {align:'center', lineHeightFactor:1.6});
    y += 30;

    // ════════════════════════════════════════════════════════════════════════
    // FOOTER on every page
    // ════════════════════════════════════════════════════════════════════════
    var pageCount = doc.getNumberOfPages();
    for (var p=1; p<=pageCount; p++) {
      doc.setPage(p);
      sf(DARK); doc.rect(0,PH-10,PW,10,'F');
      gf('normal'); doc.setFontSize(7.5); st([150,170,185]);
      doc.text('Prof. Filer \u2014 Full Personality Report \u2014 '+TYPE+(RPT.typeName?' \u2014 '+RPT.typeName:''), MAR, PH-4);
      doc.text('Page '+p+' of '+pageCount, PW-MAR, PH-4, {align:'right'});
    }

    doc.save('Prof_Filer_'+TYPE+'_Full_Report.pdf');
    if (triggerBtn) { triggerBtn.disabled=false; triggerBtn.innerHTML='&#8681; Download Full Report PDF'; }

  } catch(err) {
    console.error('PDF error:', err);
    alert('PDF generation failed: '+err.message+'\nSee console for details.');
    if (triggerBtn) { triggerBtn.disabled=false; triggerBtn.innerHTML='&#8681; Download Full Report PDF'; }
  }
}

// ── Type-specific content database ───────────────────────────────────────
function getTypeData(type) {
  var db = {
    ENTJ: {
      blurb: 'ENTJs make up approximately 2-5% of the population and are more commonly found among men than women. They are often found in leadership roles across business, politics, and entrepreneurship.',
      overview: [
        'ENTJs are natural-born leaders known for their strategic mindset, assertiveness, and ability to organize complex projects. They see the world as a landscape of opportunities to be shaped and optimized. Driven by a desire to achieve and lead, ENTJs thrive on challenges that require quick thinking and decisive action. They are future-focused visionaries who excel at creating long-term plans and mobilizing resources to realize ambitious goals.',
        'ENTJs are energized by external interaction and tend to approach problems with a logical, analytical lens. They value competence and efficiency, often pushing themselves and those around them to higher standards. While their confidence and decisiveness can sometimes come across as domineering, their intent is usually to improve systems and outcomes. They seek meaningful impact and are motivated by success, influence, and mastery of their environment.'
      ],
      characteristics: [
        'You are a strategic thinker who excels at long-term planning and envisioning future possibilities.',
        'You naturally take charge in group settings and are comfortable leading teams toward ambitious goals.',
        'You rely on objective logic and rational analysis to make decisions, even under pressure.',
        'You prefer structured environments and like to have clear plans, milestones, and deadlines.',
        'You are highly confident and assertive, often inspiring others with your conviction and energy.',
        'You can be impatient with inefficiency or indecisiveness in others.',
        'You seek continual growth and mastery in your professional and personal life.',
        'You value competence and expect high performance from yourself and everyone around you.'
      ],
      cognitiveFunctions: [
        {label:'Dominant', name:'Extraverted Thinking (Te)', desc:'You organize the external world logically and efficiently, setting goals and implementing plans to achieve measurable results. This function manifests in your natural leadership, systems thinking, and decisive action. You are energized by getting things done, and you quickly identify inefficiencies that others overlook.'},
        {label:'Auxiliary', name:'Introverted Intuition (Ni)', desc:'Your auxiliary function helps you perceive underlying patterns and future possibilities. It supports your strategic vision by allowing you to integrate insights from disparate sources and foresee long-term outcomes. This function fuels your innovative thinking and your ability to anticipate challenges before they arise.'},
        {label:'Tertiary', name:'Extraverted Sensing (Se)', desc:'Extraverted Sensing provides awareness of your immediate environment and the ability to respond dynamically to opportunities. While less developed than your dominant functions, it helps you stay grounded in present realities and maintain the commanding physical presence that characterizes your leadership.'},
        {label:'Inferior', name:'Introverted Feeling (Fi)', desc:'Your inferior function governs your internal value system and emotional depth. Under stress, you may suppress feelings, leading to unexpected outbursts or withdrawal. Developing this function over time can significantly enhance your empathy, authenticity in relationships, and ability to inspire genuine loyalty rather than mere compliance.'},
      ],
      famous: ['Margaret Thatcher', 'Steve Jobs', 'Franklin D. Roosevelt', 'Gordon Ramsay', 'Harrison Ford', 'Napoleon Bonaparte'],
      careers: ['Executive Manager', 'Entrepreneur', 'Management Consultant', 'Corporate Strategist', 'Lawyer', 'Politician', 'Project Manager', 'Financial Analyst', 'Military Officer', 'Business Development Director'],
      relationships: {
        overview: 'In relationships, you seek partners who are confident, intelligent, and independent. You value mutual respect and shared ambition, often taking a leadership role in the partnership. You appreciate clear communication and practical support, and you expect loyalty and competence from your loved ones. You are at your best with a partner who can hold their own, challenge your thinking, and match your drive.',
        friendships: 'You tend to form friendships with like-minded individuals who share your drive and intellectual curiosity. You prefer quality over quantity, valuing friends who challenge you and contribute to your growth. Your directness can sometimes intimidate more sensitive people, but those who appreciate candor find you a deeply reliable and stimulating friend.',
        romantic: 'In romantic relationships, you seek a partner who complements your ambition and can engage with you intellectually and emotionally. You value honesty and directness, and you are most satisfied when your partner supports your goals while maintaining their own identity. Emotional vulnerability may not come naturally, but it is the key that unlocks deeper intimacy and lasting connection.',
        parenting: 'As a parent, you encourage independence, responsibility, and high achievement in your children. You set clear expectations and model strong leadership. While emotional expression may not always feel natural, your children benefit enormously from your deep investment in their success, your high standards, and the sense of security your commitment provides.'
      },
      compatible: [
        'INFP \u2014 Complements your logic with emotional depth, values, and a rich inner world.',
        'ISFP \u2014 Offers warmth, groundedness, and flexibility that balances your strategic intensity.',
        'ENFP \u2014 Brings contagious enthusiasm and creative energy that enlivens your long-term plans.',
        'INTP \u2014 Shares your love for ideas, strategic thinking, and intellectual independence.'
      ],
      decisionMaking: 'You approach decisions with a focus on objective logic and efficiency, prioritizing what will yield the best results. You gather information strategically, filtering out irrelevant details to concentrate on the critical factors that impact your goals. You are comfortable making quick decisions, especially under pressure, and you hold yourself and others accountable for execution. While you value data, you also rely on your powerful intuition to foresee long-term consequences. You tend to avoid decisions driven solely by emotion, preferring clear rationale and measurable outcomes. This approach helps you lead confidently but benefits from deliberate consideration of emotional and relational factors in interpersonal contexts.',
      learningStyle: 'You learn best through conceptual frameworks and strategic overviews rather than rote memorization. You enjoy exploring theories, patterns, and future possibilities, integrating new knowledge into your existing mental models with impressive speed. Hands-on application and real-world problem solving enhance your retention and engagement significantly. You prefer self-directed learning that challenges your intellect and allows you to set clear objectives. Collaborative learning with equally driven peers can stimulate your motivation, though you will naturally gravitate toward leading discussions rather than following.',
      leadership: 'Your leadership style is visionary, assertive, and relentlessly results-oriented. You set ambitious standards, create clear and actionable plans, and motivate teams through your personal confidence and strategic insight. You naturally take charge of complex situations and expect competence and accountability from every team member. Your greatest leadership strength is the ability to see the big picture while managing the operational details that bring a vision to life. Challenges include moving faster than your team can follow, a preference for your own judgment over others\u2019 input, and the risk of substituting drive for genuine emotional connection. Leaders who combine your decisiveness with authentic empathy consistently outperform those who rely on authority alone.',
      stress: 'Under stress, you may become overly critical, impatient, or domineering, intensifying your drive to control outcomes when uncertainty increases. You might suppress emotions, which can build into unexpected reactions or abrupt withdrawal. Physical tension often manifests in your body before you recognize it mentally. To recover effectively, you benefit from stepping back to reflect quietly, engaging in vigorous physical activity, and seeking trusted confidants who can provide emotional grounding without judgment. Rest, nature, and deliberate disconnection from productivity pressures are your most underutilized recovery tools.',
      environment: 'You thrive in fast-paced, intellectually challenging environments where you can lead, strategize, and implement meaningful change. Structured workplaces with clear goals, high standards, and genuine opportunities for advancement suit you best. You need autonomy and decision-making authority to perform at your highest level. Bureaucracy, micromanagement, and environments that reward mediocrity are genuinely draining. The ideal context gives you a bold mandate, capable people to work with, and the freedom to pursue outcomes in your own way.',
      growth: [
        'Practice active empathy: deliberately pause to understand how others are experiencing a situation before offering your analysis or solution.',
        'Develop tolerance for ambiguity \u2014 not every decision requires the full picture before moving forward.',
        'Invite dissent from your team; the most useful feedback often comes from the people you are least likely to ask.',
        'Set clear personal boundaries to prevent the overcommitment that leads to diminishing returns and relationship strain.',
        'Work deliberately on your Introverted Feeling \u2014 journaling, therapy, or deep one-on-one conversations can accelerate this significantly.',
        'Celebrate process and effort, not just outcomes. This shift transforms your impact on team culture and genuine loyalty.'
      ],
      workLife: [
        'Schedule non-negotiable recovery time protected from work intrusion \u2014 treat it as seriously as your most important meeting.',
        'Create explicit boundaries between professional and personal time; your effectiveness at work depends on genuine rest.',
        'Delegate not just tasks but responsibility \u2014 developing capable people is one of your highest-leverage activities.',
        'Incorporate regular vigorous physical exercise, which directly enhances cognitive performance and emotional regulation.',
        'Practice mindfulness or reflective journaling to develop the emotional self-awareness your inferior function underserves.',
        'Prioritize sleep and nutritional quality \u2014 the sustained performance you demand of yourself requires a robust physical foundation.'
      ],
      habits: [
        'Begin each morning by reviewing your top three priorities and identifying any dependencies or blockers.',
        'Engage in deep, focused work blocks with full distraction management for your most cognitively demanding tasks.',
        'Schedule short, deliberate recovery breaks between high-intensity work periods to sustain performance.',
        'Allocate time each day for one meaningful interpersonal connection \u2014 relationship equity is a long-term strategic asset.',
        'Reserve 20 minutes at end of day for planning tomorrow and reviewing what worked, what did not, and why.',
        'Commit to a regular physical activity practice that challenges you and provides genuine psychological recovery.'
      ],
      motivations: [
        'Achieving ambitious, measurable goals that represent genuine impact rather than incremental progress.',
        'Leading and influencing others toward a vision that is larger than any individual contribution.',
        'Creating efficient, elegant systems that endure and scale beyond your direct involvement.',
        'Mastering complex challenges that require sustained intellectual effort and strategic thinking.',
        'Earning the respect of people whose competence and judgment you genuinely admire.',
        'Building a lasting legacy of meaningful contribution \u2014 something worth having existed.'
      ],
      fears: [
        'Loss of control or authority in situations where the stakes are highest.',
        'Being perceived as incompetent, unprepared, or intellectually outmatched.',
        'Failure to achieve goals that represent your deepest sense of purpose and potential.',
        'Emotional vulnerability leading to a loss of the rationality you depend on.',
        'Dependence on people whose competence or commitment does not meet your standards.',
        'Stagnation \u2014 the sense that growth has stopped and meaningful challenge has been exhausted.'
      ],
    },
    ESTJ: {
      blurb: 'ESTJs make up approximately 8-12% of the general population and are more commonly found among men. They often gravitate toward roles that require leadership and organization, reflecting their formidable natural talents.',
      overview: [
        'The ESTJ personality type, often called the Executive, is characterized by a strong sense of duty, practicality, and leadership. You see the world as a place that requires order and structure, and you naturally step into roles where you can organize, manage, and lead others. Your approach to life is grounded in facts and experience, and you value traditions, rules, and systems that have proven effective.',
        'You are driven by a desire to achieve tangible results and to uphold high standards, which makes you a deeply dependable and respected figure in both your professional and personal circles. Your natural confidence and decisiveness inspire trust, and you often become the go-to person for problem-solving and leadership.'
      ],
      characteristics: [
        'You are highly practical and grounded, focusing on what is tangible, proven, and real.',
        'You have a strong preference for structure, order, and clear rules that everyone understands.',
        'You naturally take on leadership roles and genuinely enjoy organizing people and projects.',
        'You make decisions based on logic and objective analysis rather than feelings or sentiment.',
        'You have a strong work ethic and are reliably consistent in fulfilling your commitments.',
        'You communicate in a clear, direct, and assertive manner that minimizes ambiguity.',
        'You value tradition and proven methods, often respecting established systems and institutions.',
        'You prefer to plan and decide promptly, maintaining the control and order that enables execution.'
      ],
      cognitiveFunctions: [
        {label:'Dominant', name:'Extraverted Thinking (Te)', desc:'Your dominant function drives you to organize your external world efficiently and effectively. You prioritize objective data, logical systems, and measurable results. This manifests as your natural ability to lead teams, create order from chaos, and implement practical solutions with speed and precision.'},
        {label:'Auxiliary', name:'Introverted Sensing (Si)', desc:'Introverted Sensing grounds your decisions in past experiences and established facts, providing a rich library of reliable data drawn from what has actually worked. It helps you maintain valuable traditions and lean on proven methods, providing a stable and dependable framework for your practical worldview.'},
        {label:'Tertiary', name:'Extraverted Intuition (Ne)', desc:'Your tertiary function occasionally opens the door to possibilities and alternative perspectives. While not your natural mode, it allows you to consider new ideas or adapt when circumstances genuinely require innovation. Developing this function deliberately can significantly broaden your strategic toolkit.'},
        {label:'Inferior', name:'Introverted Feeling (Fi)', desc:'Your inferior function governs your internal value system and emotional depth. Under stress, you may struggle to understand or express your feelings, sometimes creating internal bottlenecks that manifest as rigidity or frustration. Developing this function over time helps you connect more authentically with yourself and the people who matter to you.'},
      ],
      famous: ['Margaret Thatcher', 'John D. Rockefeller', 'Judge Judy Sheindlin', 'George W. Bush', 'Sonia Sotomayor', 'Franklin D. Roosevelt'],
      careers: ['Project Manager', 'Military Officer', 'Judge', 'Police Officer', 'Business Executive', 'Accountant', 'Civil Engineer', 'Operations Manager', 'Administrator', 'Financial Analyst'],
      relationships: {
        overview: 'You approach relationships with a strong sense of commitment and responsibility. You seek partners who value stability, loyalty, and shared practical goals. You tend to be deeply dependable and expect the same reliability from your loved ones. Your love language is reliability, consistency, and showing up \u2014 and you are remarkably good at all three.',
        friendships: 'In friendships, you are loyal, direct, and deeply supportive when it counts. You prefer clear boundaries and mutual respect, and you genuinely enjoy socializing in structured settings where expectations are understood. You are the friend who organizes the gathering, follows through on plans, and can always be counted on in a practical crisis.',
        romantic: 'Romantically, you are straightforward and prefer to express love through actions and commitment rather than flowery words. You value honesty, consistency, and clear communication, and you bring remarkable steadiness to relationships. Emotional vulnerability is an area of growth \u2014 learning to share your inner world, not just your plans and reliability, deepens the intimacy that sustains long-term partnerships.',
        parenting: 'As a parent, you emphasize discipline, routine, and teaching practical life skills that prepare your children for the real world. You strive to instill values of responsibility and hard work, often setting clear expectations for behavior and follow-through. Your children benefit from your consistency, your high standards, and your tangible investment in their readiness for adult life.'
      },
      compatible: [
        'ISFP \u2014 Offers warmth, flexibility, and emotional depth that complements your structured approach.',
        'INFP \u2014 Brings emotional intelligence and values-driven perspective that enriches your practical world.',
        'ISTP \u2014 Shares your preference for practical action and logical problem-solving with less interpersonal friction.',
        'ESFJ \u2014 Matches your sociability, care for community, and deep respect for tradition and shared values.'
      ],
      decisionMaking: 'You make decisions by gathering concrete data and evaluating options logically and systematically. You prioritize efficiency and effectiveness, aiming for solutions that produce measurable, real-world results. You tend to decide quickly once you have sufficient information, strongly preferring closure to ambiguity. Your approach is pragmatic and experience-grounded, drawing on what has worked in similar situations. While you value input from others, you ultimately rely on objective criteria rather than emotional considerations. This consistency and confidence in decision-making is a genuine leadership strength, though the occasional integration of emotional and abstract factors can enrich your choices in ways that pure logic cannot.',
      learningStyle: 'You learn best through hands-on experience and practical application in real-world contexts. You prefer structured learning environments with clear objectives, measurable progress, and a direct line between effort and outcome. Repetition and concrete examples help you internalize information effectively and build genuine competence. You may resist abstract or theoretical content until its practical value becomes clear. Collaborative environments where you can organize and lead discussions suit your style well. You appreciate direct and constructive feedback that allows you to improve specific skills with precision.',
      leadership: 'Your leadership style is assertive, organized, and relentlessly results-driven. You set clear expectations, hold people accountable with consistency, and create the structural conditions under which teams can perform at their best. You lead by visible example, demonstrating reliability, discipline, and the willingness to do whatever you ask others to do. Your greatest strengths are creating order, maintaining momentum, and ensuring that commitments are honored. The primary growth edge for ESTJ leaders is cultivating genuine openness to feedback, making space for emotional dynamics within the team, and developing the flexibility to adapt when the established approach is no longer the right one.',
      stress: 'When stressed, you may become overly controlling, rigid, or critical, particularly when situations feel chaotic or ungoverned. You might suppress emotional responses, which can build internal tension that eventually manifests as frustration, impatience, or uncharacteristic outbursts. To recover your equilibrium, you benefit from structured downtime that follows predictable rhythms, vigorous physical activity that releases accumulated tension, and safe environments where you can express what you are feeling without judgment.',
      environment: 'You thrive in environments that are organized, goal-oriented, and where roles, responsibilities, and expectations are clearly defined and consistently upheld. Settings that reward efficiency, reliability, and leadership suit you best, where your investment in standards is recognized and respected. You perform at your highest level when you have genuine autonomy to implement practical solutions and when your efforts contribute to measurable, tangible outcomes that you can point to with justified pride.',
      growth: [
        'Practice flexibility by exploring alternative perspectives and new approaches before committing to the established method.',
        'Develop emotional self-awareness through deliberate practices like journaling, therapy, or honest conversations with trusted confidants.',
        'Cultivate active patience for others who work differently or more slowly \u2014 diverse paces and approaches often yield insights you would miss.',
        'Encourage collaborative leadership by genuinely inviting input and dissent rather than seeking confirmation of decisions already made.',
        'Engage seriously with abstract or theoretical ideas; some of the most practically valuable insights begin as theories.',
        'Build regular renewal practices into your routine to sustain long-term effectiveness without the cost of burnout.'
      ],
      workLife: [
        'Establish clear, enforced boundaries between work time and personal time to prevent the creep that undermines both.',
        'Schedule consistent leisure and recovery activities with the same seriousness you apply to professional commitments.',
        'Delegate responsibility meaningfully \u2014 not just tasks \u2014 to develop capable people and free yourself for higher-leverage work.',
        'Build regular mindfulness or relaxation practices into your routine to manage accumulated stress before it compounds.',
        'Intentionally prioritize key relationships and social connections outside of work; they are essential to your long-term wellbeing.',
        'Periodically review whether your daily priorities are aligned with your deepest values, not just your most pressing obligations.'
      ],
      habits: [
        'Begin each day with a prioritized task list that distinguishes between urgent, important, and delegable items.',
        'Engage in regular physical activity that genuinely challenges you and provides psychological as well as physical recovery.',
        'Set aside dedicated time for reflection to build the emotional self-awareness your type consistently undervalues.',
        'Practice clear and direct communication that includes active listening, not just effective transmission of your views.',
        'Review your progress regularly against clear metrics, and adjust your strategies when data and experience warrant it.',
        'Schedule deliberate breaks across the day \u2014 recovery is not a luxury but a performance requirement.'
      ],
      motivations: [
        'Creating and maintaining order and structure that makes complex things work reliably and well.',
        'Fulfilling your commitments with the consistency and reliability that defines your character.',
        'Leading and organizing teams and systems toward shared goals with measurable excellence.',
        'Seeing tangible, real-world results that validate the effort and discipline you invest.',
        'Respecting and upholding the traditions and proven methods that have demonstrated their worth.',
        'Being recognized as genuinely competent, dependable, and worthy of the trust others place in you.'
      ],
      fears: [
        'Loss of control, chaos, or circumstances that undermine your plans and standards.',
        'Being seen as incompetent, unreliable, or failing to meet the expectations you set for yourself.',
        'Inefficiency, wasted effort, and the frustration of seeing capable people underperform.',
        'Emotional vulnerability being mistaken for weakness or loss of authority.',
        'Failure to meet your obligations or to disappoint the people who are counting on you.',
        'Change that threatens established systems and proven ways of working.'
      ],
    },
  };

  var defaults = {
    blurb: 'Your '+type+' personality profile has been prepared by Prof. Filer using AI-powered analysis of your quiz answers and writing style.',
    overview: ['You have a distinctive personality that shapes how you engage with the world, process information, and make decisions. Prof. Filer has analyzed your responses to build a comprehensive picture of your unique strengths, growth opportunities, and inner landscape.'],
    characteristics: ['You have a clear and consistent way of engaging with the world around you.','Your decision-making style reflects your core personality preferences and values.','You bring genuine and distinctive strengths to both professional and personal relationships.','You have areas of natural ease and areas where your greatest growth awaits.'],
    cognitiveFunctions: [
      {label:'Dominant', name:'Primary Function', desc:'Your dominant cognitive function is the primary lens through which you experience and process the world. It represents your most natural and effortless mode of engaging with information and making decisions.'},
      {label:'Auxiliary', name:'Supporting Function', desc:'Your auxiliary function provides balance and depth to your personality. It supports your dominant function and helps you interact effectively and adaptively with others.'},
      {label:'Tertiary', name:'Developing Function', desc:'Your tertiary function is less developed but continues to emerge throughout your adult life, adding nuance and flexibility to how you see and engage with the world.'},
      {label:'Inferior', name:'Shadow Function', desc:'Your inferior function often emerges under stress. Developing awareness of it and intentionally engaging with it can deepen self-understanding and build genuine psychological resilience.'},
    ],
    famous: ['Leaders, innovators, and creatives across history share aspects of your personality profile.'],
    careers: ['Leadership roles','Strategic management','Consulting and advisory work','Analysis and research','Creative professions','People-focused and service professions'],
    relationships: {
      overview: 'In relationships, you bring consistency in your values, genuine care for the people close to you, and a distinctive way of showing up when it matters most.',
      friendships: 'You invest deeply in the friendships that matter, valuing quality of connection over breadth of social network. You are more loyal than you may appear, and you show that loyalty through reliability and presence.',
      romantic: 'In romantic relationships, you seek a partner who understands and genuinely complements your personality. You have a distinctive way of expressing love and a clear sense of what you need to feel fulfilled and truly seen.',
      parenting: 'As a parent, you bring your core personality strengths to the raising of your children, instilling the values and capabilities that matter most deeply to you.'
    },
    compatible: ['Compatible types are those who complement your strengths and provide balance in the areas where you naturally grow.'],
    decisionMaking: 'You make decisions in a way that reflects your core personality type, drawing on your natural strengths and applying the wisdom accumulated through your experience and reflection.',
    learningStyle: 'You learn in ways that align with your personality preferences, gravitating toward approaches that feel natural and effective given how your mind processes and retains information.',
    leadership: 'Your leadership style reflects your personality type: you lead with your natural strengths, build on the respect of those around you, and continue to develop the dimensions that round out your effectiveness as a leader over time.',
    stress: 'Under stress, your personality type tends toward specific and recognizable patterns. Developing awareness of these patterns is the foundational step toward building healthier and more effective coping strategies that serve you and those around you.',
    environment: 'You thrive in environments that align with your natural personality preferences and create the conditions for you to operate from your core strengths with genuine confidence and satisfaction.',
    growth: [
      'Develop awareness of your natural blind spots and the patterns that limit your full effectiveness.',
      'Actively seek input from people whose strengths complement yours and whose perspective differs from your own.',
      'Practice the approaches that feel least natural to your type \u2014 this is where your most significant growth lives.',
      'Build genuine flexibility into your routines and decision-making processes to enhance your range and resilience.'
    ],
    workLife: [
      'Set meaningful boundaries that protect both your energy and your most important relationships.',
      'Schedule consistent time for the activities that genuinely recharge and restore you.',
      'Delegate tasks that drain you to those better suited and positioned to handle them.',
      'Prioritize both sustained productivity and genuine, restorative rest \u2014 you need both to perform at your best.'
    ],
    habits: [
      'Begin each day with clear intention and a small number of meaningful priorities.',
      'Build time for honest reflection alongside time for focused action.',
      'Nurture the connections with people who genuinely energize and challenge you.',
      'End each day acknowledging real progress, however incremental it may appear.'
    ],
    motivations: [
      'Living in authentic alignment with your core values and sense of purpose.',
      'Contributing meaningfully to your work and to the lives of the people around you.',
      'Growing continuously in self-understanding, capability, and genuine impact.',
      'Connecting with others in ways that feel genuine and mutually enriching.'
    ],
    fears: [
      'Being misunderstood or unseen for who you genuinely are.',
      'Losing the relationships and sense of purpose that anchor you.',
      'Stagnation \u2014 the absence of meaningful growth or forward movement in your life.',
      'Conflict that damages the relationships that matter most to you.'
    ],
  };

  return db[type] || defaults;
}

function retakeQuiz(){ QP='intro';QC=0;QA={};QR='';DOCS=[];RPT={};renderQuiz(); }
function copyReport(){ if(navigator.clipboard) navigator.clipboard.writeText(QR).then(function(){alert('Copied!');}); }
function qsa(id,v){ QA[id]=v; renderQuiz(); }
function qprev(){ if(QC>0){ QC--;renderQuiz(); } }
function qnext(){
  var q=QS[QC];
  if(QA[q.id]===undefined) return;
  if(QC<QS.length-1){ QC++;renderQuiz(); }
  else { QP='docs'; renderQuiz(); }
}

function submitQuiz(){
  QP='loading'; renderQuiz();
  var lines=[];
  for(var i=0;i<QS.length;i++){
    var q=QS[i],a=QA[q.id],at='';
    if(q.t==='r'){ var idx=['A','B','C','D'].indexOf(a); at=idx>=0?q.os[idx]:String(a); }
    else if(q.t==='s'){ at=a+'/10 ('+q.lo+' to '+q.hi+')'; }
    else{ at=a+'/5 stars'; }
    lines.push('Q'+q.id+': '+q.q+'\nAnswer: '+at);
  }
  var docNote = DOCS.length>0?'\n\nDocuments uploaded for writing style analysis: '+DOCS.join(', '):'';
  var prompt = [
    'You are Prof. Filer, a warm, witty, and incisive personality analyst.',
    'Based on these quiz answers, write a personality assessment report.',
    '',
    lines.join('\n\n')+docNote,
    '',
    'Use these EXACT headings verbatim:',
    '',
    '**Your Personality Type**',
    '[4-letter MBTI type e.g. ENTJ] \u2014 [Profile name e.g. The Commander] \u2014 [3-word descriptor e.g. Bold and Strategic]',
    '',
    "**The Prof.'s Reading**",
    '[Write 3 substantial paragraphs. Be specific to THEIR answers, not generic. First paragraph: their energy and social orientation based on Q1, Q7. Second paragraph: how they process information and make decisions based on Q2, Q3, Q6, Q8. Third paragraph: their approach to structure and conflict based on Q4, Q5, Q9, Q10. Be warm, perceptive, occasionally witty.]',
    '',
    '**Your Superpowers**',
    '\u2022 [Name the strength]: [1-2 sentence explanation tied to their specific answers]',
    '\u2022 [Name the strength]: [1-2 sentence explanation tied to their specific answers]',
    '\u2022 [Name the strength]: [1-2 sentence explanation tied to their specific answers]',
    '',
    '**Watch Out For**',
    '\u2022 [Name the blind spot]: [1-2 sentence warm, constructive explanation]',
    '\u2022 [Name the blind spot]: [1-2 sentence warm, constructive explanation]',
    '',
    "**Prof. Filer's Verdict**",
    '[One memorable, quotable sentence that captures this person\'s essence. Make it feel personal and distinctive, not generic.]',
    '',
    'Tone: smart, warm, slightly witty, deeply perceptive. Like a brilliant friend who also happens to be a psychologist. Never generic.',
  ].join('\n');

  fetch('/api/analyze',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({model:'gpt-4o',max_tokens:1400,messages:[{role:'user',content:prompt}]})
  })
  .then(function(res){ return res.json(); })
  .then(function(d){
    if(d.error){ QR='API error: '+(typeof d.error==='string'?d.error:JSON.stringify(d.error)); }
    else{ var blk=d.content&&d.content.find(function(b){return b.type==='text';}); QR=blk?blk.text:'Unable to generate report.'; }
    QP='report'; renderQuiz();
  })
  .catch(function(e){ QR='Connection error: '+e.toString(); QP='report'; renderQuiz(); });
}
